// @flow
import optionalRequire from './Utils/OptionalRequire';
import { isNativeMobileApp } from './Utils/Platform';

// $FlowFixMe[cannot-resolve-name]
const PUBLIC_URL: string = process.env.PUBLIC_URL || '';
// $FlowFixMe[cannot-resolve-name]
const isDev = process.env.NODE_ENV !== 'production';

const electron = optionalRequire('electron');
const serviceWorker =
  typeof navigator !== 'undefined' ? navigator.serviceWorker : undefined;

const normalizePathPrefix = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed) return '';
  if (trimmed === '/') return '';
  return trimmed.endsWith('/') ? trimmed.slice(0, -1) : trimmed;
};

const getCurrentLocationDirectoryUrl = (): string => {
  const { origin, pathname } = window.location;
  const normalizedPathname = pathname || '/';
  const hasFileExtension = /\/[^/]+\.[^/]+$/.test(normalizedPathname);
  const directoryPath = normalizedPathname.endsWith('/')
    ? normalizedPathname
    : hasFileExtension
    ? normalizedPathname.replace(/\/[^/]*$/, '/')
    : `${normalizedPathname}/`;

  return `${origin}${directoryPath}`;
};

const getServiceWorkerPublicBase = (): string => {
  const normalizedPublicUrl = normalizePathPrefix(PUBLIC_URL || '');

  if (!normalizedPublicUrl || normalizedPublicUrl === '.') {
    return normalizePathPrefix(getCurrentLocationDirectoryUrl());
  }

  try {
    const resolvedPublicUrl = new URL(normalizedPublicUrl, window.location.href);
    return normalizePathPrefix(
      `${resolvedPublicUrl.origin}${resolvedPublicUrl.pathname}`
    );
  } catch {
    return normalizedPublicUrl;
  }
};

const getServiceWorkerScriptUrl = (): string => {
  const publicBase = getServiceWorkerPublicBase();
  if (!publicBase) return '/service-worker.js';

  return `${publicBase}/service-worker.js`;
};

const getServiceWorkerScope = (serviceWorkerScriptUrl: string): ?string => {
  try {
    const resolvedScriptUrl = new URL(serviceWorkerScriptUrl, window.location.href);
    const pathname = resolvedScriptUrl.pathname || '/service-worker.js';
    const scopePath = pathname.replace(/\/[^/]*$/, '/');
    return scopePath || '/';
  } catch {
    return null;
  }
};

const withTimeout = <T>(
  promise: Promise<T>,
  timeoutMs: number,
  fallbackValue: T
): Promise<T> => {
  return new Promise(resolve => {
    const timeoutId = setTimeout(() => resolve(fallbackValue), timeoutMs);
    promise
      .then(value => {
        clearTimeout(timeoutId);
        resolve(value);
      })
      .catch(() => {
        clearTimeout(timeoutId);
        resolve(fallbackValue);
      });
  });
};

const waitForControllerChange = (timeoutMs: number): Promise<boolean> => {
  if (!serviceWorker) return Promise.resolve(false);
  if (serviceWorker.controller) return Promise.resolve(true);

  return new Promise(resolve => {
    let settled = false;
    const timeoutId = setTimeout(() => {
      if (settled) return;
      settled = true;
      serviceWorker.removeEventListener('controllerchange', onControllerChange);
      resolve(!!serviceWorker.controller);
    }, timeoutMs);

    const onControllerChange = () => {
      if (settled) return;
      settled = true;
      clearTimeout(timeoutId);
      serviceWorker.removeEventListener('controllerchange', onControllerChange);
      resolve(!!serviceWorker.controller);
    };

    serviceWorker.addEventListener('controllerchange', onControllerChange);
  });
};

const unregisterAllServiceWorkers = async () => {
  if (!serviceWorker || typeof serviceWorker.getRegistrations !== 'function') {
    return;
  }
  const registrations = await serviceWorker.getRegistrations();
  await Promise.all(
    registrations.map(registration => registration.unregister())
  );
};

const handleServiceWorkerError = (context: string, error: any) => {
  if (isDev) {
    console.warn(`[ServiceWorker] ${context} failed.`, error);
    unregisterAllServiceWorkers().catch(unregisterError => {
      console.warn(
        '[ServiceWorker] Failed to cleanup existing registrations.',
        unregisterError
      );
    });
    return;
  }

  console.error(`[ServiceWorker] ${context} failed.`, error);
};

export function isServiceWorkerSupported(): boolean {
  return !!serviceWorker;
}

export async function waitForServiceWorkerController(
  timeoutMs: number = 10000
): Promise<boolean> {
  if (!serviceWorker) return false;
  if (serviceWorker.controller) return true;

  const startTime = Date.now();
  const readyRegistration = await withTimeout(
    serviceWorker.ready,
    timeoutMs,
    null
  );

  if (readyRegistration && typeof readyRegistration.update === 'function') {
    try {
      await readyRegistration.update();
    } catch (error) {
      if (isDev) {
        console.warn(
          '[ServiceWorker] Unable to update service worker registration before launching preview.',
          error
        );
      }
    }
  }

  if (serviceWorker.controller) return true;

  const elapsed = Date.now() - startTime;
  const remainingTimeout = Math.max(1000, timeoutMs - elapsed);
  return waitForControllerChange(remainingTimeout);
}

export function registerServiceWorker() {
  if (isNativeMobileApp() || !!electron) {
    return;
  }

  if (!serviceWorker) {
    console.warn(
      'Service Worker not supported on this deployment (probably: not HTTPS and not localhost).'
    );
    return;
  }

  const register = () => {
    // Use a cache-buster for development so that the service worker is
    // always reloaded when the app is reloaded.
    const serviceWorkerScriptUrl = getServiceWorkerScriptUrl();
    const swUrl = isDev
      ? `${serviceWorkerScriptUrl}?dev=${Date.now()}`
      : serviceWorkerScriptUrl;
    const scope = getServiceWorkerScope(serviceWorkerScriptUrl);
    const registerPromise = scope
      ? serviceWorker.register(swUrl, { scope })
      : serviceWorker.register(swUrl);

    registerPromise
      .then(registration => {
        registration.onupdatefound = () => {
          const installingWorker = registration.installing;
          if (installingWorker == null) {
            return;
          }
          installingWorker.onstatechange = () => {
            if (installingWorker.state === 'installed') {
              const alreadyHasAServiceWorker = !!serviceWorker.controller;
              if (!isDev) {
                if (alreadyHasAServiceWorker) {
                  // At this point, the updated precached content has been fetched,
                  // but the previous service worker will still serve the older
                  // content until all client tabs are closed.
                  console.log(
                    'A new version is available and will be used when all tabs for this page are closed.'
                  );
                } else {
                  // Service worker has been installed for the first time.
                  console.log('Content is cached for offline use.');
                }
              }
            }
          };
        };
      })
      .catch(error => handleServiceWorkerError('registration', error));

    serviceWorker.ready
      .then(registration => {
        // Forces a check right now for a newer service worker script.
        // If there is one, it will be installed (see the service worker script to verify how in development
        // a new service worker script does a `self.skipWaiting()` and `self.clients.claim()`).
        return registration.update();
      })
      .catch(error => handleServiceWorkerError('ready/update', error));
  };

  if (document.readyState === 'complete') {
    register();
    return;
  }

  window.addEventListener('load', register, { once: true });
}
